css:
.nav-cards {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: 20px;
    margin: 20px 0;
}
.nav-card {
    display: block;
    border: 1px solid #eee;
    border-radius: 8px;
    overflow: hidden;
    text-decoration: none;
    color: inherit;
    transition: transform 0.2s;
    background: #fff;
}
.nav-card:hover { transform: translateY(-5px); box-shadow: 0 4px 15px rgba(0,0,0,0.1); }
.nav-card-img img {
    width: 100%;
    height: 180px;
    object-fit: cover;
    display: block;
}
.nav-card-content { padding: 15px; }
.nav-card-title { margin: 0 0 8px; font-size: 1.2rem; color: #333; }
.nav-card-desc { font-size: 0.9rem; color: #666; margin: 0 0 8px; line-height: 1.5; }
.nav-card-date { font-size: 0.8rem; color: #999; margin: 0; }
.nav-card.active { outline: 2px solid #f97316; }
